cleaned_rows as (
  select
    nullif(id, '')::uuid as id,
    nullif(commercial_id, '') as commercial_id,
    nullif(client_name, '') as client_name,
    nullif(clinic_name, '') as clinic_name,
    nullif(plan, '') as plan,
    nullif(deal_value, '')::numeric as deal_value,
    nullif(creative_source, '') as creative_source,
    CASE
  WHEN nullif(team_id, '') IS NOT NULL
   AND nullif(team_id, '') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[089ab][0-9a-f]{3}-[0-9a-f]{12}$'
   AND EXISTS (SELECT 1 FROM public.teams x WHERE x.id = nullif(team_id, '')::uuid)
  THEN nullif(team_id, '')::uuid
  ELSE null
END as team_id,
    CASE
  WHEN nullif(assigned_gestor_id, '') IS NOT NULL
   AND nullif(assigned_gestor_id, '') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[089ab][0-9a-f]{3}-[0-9a-f]{12}$'
   AND EXISTS (SELECT 1 FROM public.profiles x WHERE x.id = nullif(assigned_gestor_id, '')::uuid)
  THEN nullif(assigned_gestor_id, '')::uuid
  ELSE null
END as assigned_gestor_id,
    CASE
  WHEN nullif(assigned_atendente_id, '') IS NOT NULL
   AND nullif(assigned_atendente_id, '') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[089ab][0-9a-f]{3}-[0-9a-f]{12}$'
   AND EXISTS (SELECT 1 FROM public.profiles x WHERE x.id = nullif(assigned_atendente_id, '')::uuid)
  THEN nullif(assigned_atendente_id, '')::uuid
  ELSE null
END as assigned_atendente_id,
    CASE
  WHEN nullif(assigned_design_id, '') IS NOT NULL
   AND nullif(assigned_design_id, '') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[089ab][0-9a-f]{3}-[0-9a-f]{12}$'
   AND EXISTS (SELECT 1 FROM public.profiles x WHERE x.id = nullif(assigned_design_id, '')::uuid)
  THEN nullif(assigned_design_id, '')::uuid
  ELSE null
END as assigned_design_id,
    CASE
  WHEN nullif(assigned_editor_video_id, '') IS NOT NULL
   AND nullif(assigned_editor_video_id, '') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[089ab][0-9a-f]{3}-[0-9a-f]{12}$'
   AND EXISTS (SELECT 1 FROM public.profiles x WHERE x.id = nullif(assigned_editor_video_id, '')::uuid)
  THEN nullif(assigned_editor_video_id, '')::uuid
  ELSE null
END as assigned_editor_video_id,
    nullif(status_operacional, '') as status_operacional,
    nullif(stage_trafego, '') as stage_trafego,
    nullif(stage_atendimento, '') as stage_atendimento,
    nullif(stage_marketing, '') as stage_marketing,
    nullif(onboarding_start_at, '')::timestamptz as onboarding_start_at,
    nullif(onboarding_done_at, '')::timestamptz as onboarding_done_at,
    nullif(created_at, '')::timestamptz as created_at,
    nullif(updated_at, '')::timestamptz as updated_at,
    nullif(activated_at, '')::timestamptz as activated_at,
    CASE
  WHEN nullif(activated_by, '') IS NOT NULL
   AND nullif(activated_by, '') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[089ab][0-9a-f]{3}-[0-9a-f]{12}$'
  THEN nullif(activated_by, '')::uuid
  ELSE null
END as activated_by,
    nullif(onboarding_stage, '') as onboarding_stage,
    nullif(briefing_completed_at, '')::timestamptz as briefing_completed_at,
    nullif(churn_status, '') as churn_status,
    nullif(churn_reason, '') as churn_reason,
    CASE
  WHEN nullif(churn_responsible_team_id, '') IS NOT NULL
   AND nullif(churn_responsible_team_id, '') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[089ab][0-9a-f]{3}-[0-9a-f]{12}$'
   AND EXISTS (SELECT 1 FROM public.teams x WHERE x.id = nullif(churn_responsible_team_id, '')::uuid)
  THEN nullif(churn_responsible_team_id, '')::uuid
  ELSE null
END as churn_responsible_team_id,
    nullif(churn_date, '')::timestamptz as churn_date,
    nullif(renewal_status, '') as renewal_status,
    nullif(renewal_date, '')::timestamptz as renewal_date,
    CASE
  WHEN nullif(renewal_responsible_team_id, '') IS NOT NULL
   AND nullif(renewal_responsible_team_id, '') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[089ab][0-9a-f]{3}-[0-9a-f]{12}$'
   AND EXISTS (SELECT 1 FROM public.teams x WHERE x.id = nullif(renewal_responsible_team_id, '')::uuid)
  THEN nullif(renewal_responsible_team_id, '')::uuid
  ELSE null
END as renewal_responsible_team_id,
    nullif(renewal_due_date, '')::timestamptz as renewal_due_date,
    nullif(pagador_anuncio, '') as pagador_anuncio,
    nullif(client_tier, '') as client_tier,
    nullif(pacote, '') as pacote,
    nullif(ad_account_name, '') as ad_account_name,
    CASE
  WHEN lower(nullif(has_recharge, '')) IN ('t', 'true', '1', 'sim', 'yes') THEN true
  WHEN lower(nullif(has_recharge, '')) IN ('f', 'false', '0', 'nao', 'não', 'no') THEN false
  ELSE null
END as has_recharge,
    nullif(recharge_value, '')::numeric as recharge_value,
    nullif(start_meeting_date, '')::timestamptz as start_meeting_date,
    CASE
  WHEN lower(nullif(nps_sent, '')) IN ('t', 'true', '1', 'sim', 'yes') THEN true
  WHEN lower(nullif(nps_sent, '')) IN ('f', 'false', '0', 'nao', 'não', 'no') THEN false
  ELSE null
END as nps_sent,
    CASE
  WHEN lower(nullif(nps_answered, '')) IN ('t', 'true', '1', 'sim', 'yes') THEN true
  WHEN lower(nullif(nps_answered, '')) IN ('f', 'false', '0', 'nao', 'não', 'no') THEN false
  ELSE null
END as nps_answered,
    nullif(status_updated_at, '')::timestamptz as status_updated_at
  from raw_rows
)
insert into public.operational_clients (
  id, commercial_id, client_name, clinic_name, plan, deal_value, creative_source, team_id, assigned_gestor_id, assigned_atendente_id, assigned_design_id, assigned_editor_video_id, status_operacional, stage_trafego, stage_atendimento, stage_marketing, onboarding_start_at, onboarding_done_at, created_at, updated_at, activated_at, activated_by, onboarding_stage, briefing_completed_at, churn_status, churn_reason, churn_responsible_team_id, churn_date, renewal_status, renewal_date, renewal_responsible_team_id, renewal_due_date, pagador_anuncio, client_tier, pacote, ad_account_name, has_recharge, recharge_value, start_meeting_date, nps_sent, nps_answered, status_updated_at
)
select
  id, commercial_id, client_name, clinic_name, plan, deal_value, creative_source, team_id, assigned_gestor_id, assigned_atendente_id, assigned_design_id, assigned_editor_video_id, status_operacional, stage_trafego, stage_atendimento, stage_marketing, onboarding_start_at, onboarding_done_at, created_at, updated_at, activated_at, activated_by, onboarding_stage, briefing_completed_at, churn_status, churn_reason, churn_responsible_team_id, churn_date, renewal_status, renewal_date, renewal_responsible_team_id, renewal_due_date, pagador_anuncio, client_tier, pacote, ad_account_name, has_recharge, recharge_value, start_meeting_date, nps_sent, nps_answered, status_updated_at
from cleaned_rows
on conflict (id) do nothing;
